  "cases": [
    {
      "input": {
        "table_name": "users",
        "primary_key": "id",
        "options": {
          "format_yard": true
        },
        "columns": [
          {
            "name": "id",
            "type": "integer"
          },
          {
            "name": "name",
            "type": "string",
            "limit": 50
          },
          {
            "name": "balance",
            "type": "decimal",
            "precision": 8,
            "scale": 2
