      "expected_output": "# == Schema Information\n#\n# Table name: users\n#\n# @!attribute id\n#   @return [Integer]\n# @!attribute name\n#   @return [String]\n# @!attribute balance\n#   @return []\n# @!attribute created_at\n#   @return [Time]\n#\n"
    }
  ]
}

