    {
      "input": {
        "table_name": "products",
        "primary_key": "id",
        "options": {},
        "columns": [
          {
            "name": "id",
            "type": "integer"
          },
          {
            "name": "title",
            "type": "string",
            "limit": 120
          },
          {
            "name": "price",
            "type": "decimal",
            "precision": 10,
            "scale": 2
          }
