    {
      "input": {
        "table_name": "orders",
        "primary_key": "id",
        "options": {
          "show_foreign_keys": true
        },
        "columns": [
          {
            "name": "id",
            "type": "integer"
          },
          {
            "name": "user_id",
            "type": "integer",
            "null": true
          }
        ],
        "foreign_keys": [
          {
            "name": "fk_rails_a1b2c3d4e5",
